function DrawDonut() {
  const { Pie } = components;
  const measureField = "measure_column";
  const config = {
    appendPadding: 10,
    data,
    angleField: measureField,
    colorField: "dimension_column",
    radius: 0.8,
    innerRadius: 0.6,
    statistic: {
      title: {
        style: { color: "#000", fontSize: 14 },
        formatter: () => "title_text"
      },
      content: {
        style: { fontSize: 14 },
        content: String(
          data.reduce((sum, row) => sum + (row[measureField] || 0), 0)
        )
      }
    },
    interactions: [{ type: "element-active" }]
  };
  return <div><Pie {...config} /></div>;
}
